import React, { useEffect, useState } from "react";
import api from "../services/api";

const AdminDashboard = () => {
  const [disaster, setDisaster] = useState({
    title: "",
    type: "flood",
    location: "",
    severity: "",
    description: ""
  });
  const [resource, setResource] = useState({
    name: "",
    type: "food",
    quantity: 0,
    disasterId: "",
    status: "available"
  });
  const [volunteerUpdate, setVolunteerUpdate] = useState({ id: "", assignedTask: "", status: "assigned" });
  const [disasters, setDisasters] = useState([]);
  const [resources, setResources] = useState([]);
  const [volunteers, setVolunteers] = useState([]);

  const fetchData = async () => {
    const [disasterRes, resourceRes, volunteerRes] = await Promise.all([
      api.get("/disasters"),
      api.get("/resources"),
      api.get("/volunteers")
    ]);
    setDisasters(disasterRes.data);
    setResources(resourceRes.data);
    setVolunteers(volunteerRes.data);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const createDisaster = async (e) => {
    e.preventDefault();
    await api.post("/disasters", disaster);
    setDisaster({ title: "", type: "flood", location: "", severity: "", description: "" });
    fetchData();
  };

  const addResource = async (e) => {
    e.preventDefault();
    await api.post("/resources", { ...resource, quantity: Number(resource.quantity) });
    setResource({ name: "", type: "food", quantity: 0, disasterId: "", status: "available" });
    fetchData();
  };

  const assignVolunteer = async (e) => {
    e.preventDefault();
    await api.put(`/volunteers/${volunteerUpdate.id}`, {
      assignedTask: volunteerUpdate.assignedTask,
      status: volunteerUpdate.status
    });
    setVolunteerUpdate({ id: "", assignedTask: "", status: "assigned" });
    fetchData();
  };

  return (
    <div>
      <h2>Admin Dashboard</h2>

      <h3>Create Disaster</h3>
      <form onSubmit={createDisaster}>
        <input placeholder="Title" value={disaster.title} onChange={(e) => setDisaster({ ...disaster, title: e.target.value })} required />
        <select value={disaster.type} onChange={(e) => setDisaster({ ...disaster, type: e.target.value })}>
          <option value="flood">Flood</option>
          <option value="earthquake">Earthquake</option>
          <option value="cyclone">Cyclone</option>
        </select>
        <input placeholder="Location" value={disaster.location} onChange={(e) => setDisaster({ ...disaster, location: e.target.value })} required />
        <input placeholder="Severity" value={disaster.severity} onChange={(e) => setDisaster({ ...disaster, severity: e.target.value })} required />
        <input placeholder="Description" value={disaster.description} onChange={(e) => setDisaster({ ...disaster, description: e.target.value })} required />
        <button type="submit">Create</button>
      </form>

      <h3>Add Resource</h3>
      <form onSubmit={addResource}>
        <input placeholder="Name" value={resource.name} onChange={(e) => setResource({ ...resource, name: e.target.value })} required />
        <select value={resource.type} onChange={(e) => setResource({ ...resource, type: e.target.value })}>
          <option value="food">Food</option>
          <option value="water">Water</option>
          <option value="medicine">Medicine</option>
        </select>
        <input type="number" placeholder="Quantity" value={resource.quantity} onChange={(e) => setResource({ ...resource, quantity: e.target.value })} required />
        <select value={resource.disasterId} onChange={(e) => setResource({ ...resource, disasterId: e.target.value })} required>
          <option value="">Select Disaster</option>
          {disasters.map((d) => (
            <option key={d._id} value={d._id}>
              {d.title}
            </option>
          ))}
        </select>
        <button type="submit">Add</button>
      </form>

      <h3>Assign Volunteer Task</h3>
      <form onSubmit={assignVolunteer}>
        <select value={volunteerUpdate.id} onChange={(e) => setVolunteerUpdate({ ...volunteerUpdate, id: e.target.value })} required>
          <option value="">Select Volunteer</option>
          {volunteers.map((v) => (
            <option key={v._id} value={v._id}>
              {v.userId?.name || "Volunteer"} ({v.status})
            </option>
          ))}
        </select>
        <input placeholder="Assigned Task" value={volunteerUpdate.assignedTask} onChange={(e) => setVolunteerUpdate({ ...volunteerUpdate, assignedTask: e.target.value })} required />
        <input placeholder="Status" value={volunteerUpdate.status} onChange={(e) => setVolunteerUpdate({ ...volunteerUpdate, status: e.target.value })} required />
        <button type="submit">Assign</button>
      </form>

      <h3>Resources</h3>
      <table border="1" cellPadding="6">
        <thead>
          <tr>
            <th>Name</th>
            <th>Type</th>
            <th>Quantity</th>
            <th>Status</th>
            <th>Disaster</th>
          </tr>
        </thead>
        <tbody>
          {resources.map((r) => (
            <tr key={r._id}>
              <td>{r.name}</td>
              <td>{r.type}</td>
              <td>{r.quantity}</td>
              <td>{r.status}</td>
              <td>{r.disasterId?.title || "-"}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default AdminDashboard;
